class Solution {
public:
    int getKth(int lo, int hi, int k) {
        vector<pair<int, int>> powers;
        for (int i = lo; i <= hi; ++i) {
            int power = 0;
            int x = i;
            while (x != 1) {
                if (x % 2 == 0) x /= 2;
                else x = 3 * x + 1;
                ++power;
            }
            powers.emplace_back(power, i);
        }
        sort(powers.begin(), powers.end());
        return powers[k - 1].second;
    }
};
